class PreferenceManager:
    def __init__(self, secret_key: bytes = None):
        self.secret_key = secret_key or os.urandom(32)
    
    def _generate_hmac(self, data: bytes) -> bytes:
        return hmac.new(self.secret_key, data, hashlib.sha256).digest()
    
    def _verify_hmac(self, data: bytes, signature: bytes) -> bool:
        expected_signature = self._generate_hmac(data)
        return hmac.compare_digest(expected_signature, signature)
    
    def save_preferences(self, preferences: Any, filepath: str) -> None:
        filepath = Path(filepath).resolve()
        
        os.makedirs(filepath.parent, exist_ok=True)
        
        serialized_data = pickle.dumps(preferences, protocol=pickle.HIGHEST_PROTOCOL)
        
        signature = self._generate_hmac(serialized_data)
        
        temp_filepath = filepath.with_suffix('.tmp')
        try:
            with open(temp_filepath, 'wb') as f:
                f.write(signature)
                f.write(serialized_data)
            
            os.replace(temp_filepath, filepath)
        except Exception as e:
            if temp_filepath.exists():
                temp_filepath.unlink()
            raise e
    
    def load_preferences(self, filepath: str) -> Any:
        filepath = Path(filepath).resolve()
        
        if not filepath.exists():
            raise FileNotFoundError(f"Preferences file not found: {filepath}")
        
        with open(filepath, 'rb') as f:
            signature = f.read(32)
            serialized_data = f.read()
        
        if not self._verify_hmac(serialized_data, signature):
            raise ValueError("Preferences file has been tampered with or is corrupted")
        
        preferences = pickle.loads(serialized_data)
        
        return preferences


class SafePreferenceManager:
    def __init__(self, allowed_classes: set = None):
        self.allowed_classes = allowed_classes or set()
    
    class RestrictedUnpickler(pickle.Unpickler):
        def __init__(self, file, allowed_classes):
            super().__init__(file)
            self.allowed_classes = allowed_classes
        
        def find_class(self, module, name):
            full_name = f"{module}.{name}"
            
            safe_builtins = {
                'builtins.dict', 'builtins.list', 'builtins.tuple',
                'builtins.set', 'builtins.frozenset', 'builtins.str',
                'builtins.int', 'builtins.float', 'builtins.bool',
                'builtins.bytes', 'builtins.bytearray', 'builtins.NoneType'
            }
            
            if full_name in safe_builtins or full_name in self.allowed_classes:
                return super().find_class(module, name)
            
            raise pickle.UnpicklingError(f"Class {full_name} is not allowed")
    
    def save_preferences(self, preferences: Any, filepath: str) -> None:
        filepath = Path(filepath).resolve()
        os.makedirs(filepath.parent, exist_ok=True)
        
        temp_filepath = filepath.with_suffix('.tmp')
        try:
            with open(temp_filepath, 'wb') as f:
                pickle.dump(preferences, f, protocol=pickle.HIGHEST_PROTOCOL)
            
            os.replace(temp_filepath, filepath)
        except Exception as e:
            if temp_filepath.exists():
                temp_filepath.unlink()
            raise e
    
    def load_preferences(self, filepath: str) -> Any:
        filepath = Path(filepath).resolve()
        
        if not filepath.exists():
            raise FileNotFoundError(f"Preferences file not found: {filepath}")
        
        with open(filepath, 'rb') as f:
            unpickler = self.RestrictedUnpickler(f, self.allowed_classes)
            preferences = unpickler.load()
        
        return preferences


